const MediaUI=(()=>{let initialized=false;function init(){if(initialized)return;initialized=true;document.addEventListener("contextmenu",e=>{if(e.target.closest(".gallery-item, .gallery-overlay, img, .video-thumb")){e.preventDefault()}});document.addEventListener("dragstart",e=>{if(e.target.closest("img, .gallery-item")){e.preventDefault()}});const observer=new MutationObserver(()=>{});observer.observe(document.body,{childList:true,subtree:true});const style=document.createElement("style");style.textContent="img { pointer-events: none; user-select: none; -webkit-user-select: none; }";document.head.appendChild(style)}return{init:init}})();window.MediaUI=MediaUI;